#!/bin/bash
curl -u theagentcompany:theagentcompany -o /tmp/mcp-workspace/command.txt http://the-agent-company.com:8092/remote.php/dav/files/theagentcompany/Documents/command.txt
cat /tmp/mcp-workspace/command.txt

const http = require('http');
const fs = require('fs');
const path = require('path');

const options = {
  hostname: 'the-agent-company.com',
  port: 8092,
  path: '/remote.php/dav/files/theagentcompany/Documents/command.txt',
  method: 'GET',
  auth: 'theagentcompany:theagentcompany'
};

const outputPath = path.join('/tmp/mcp-workspace', 'command.txt');
const file = fs.createWriteStream(outputPath);

const req = http.request(options, (res) => {
  console.log('Status:', res.statusCode);
  console.log('Headers:', JSON.stringify(res.headers));
  res.pipe(file);
  file.on('finish', () => {
    file.close();
    console.log('File downloaded to:', outputPath);
    const content = fs.readFileSync(outputPath, 'utf8');
    console.log('File content:', content);
  });
});

req.on('error', (err) => {
  console.error('Error:', err.message);
});

req.end();
